import { useRef, useEffect } from 'react';

// 同一时刻只允许一路音频播放
let _activeAudio = null;

export function stopGlobalAudio() {
  if (!_activeAudio) return;
  _activeAudio.pause();
  _activeAudio = null;
}

/**
 * useAudioPlayer
 * @returns {{ audioRef, syncPromiseRef }}
 *   syncPromiseRef.current — Promise<HTMLAudioElement>，canplay 后 resolve
 */
export function useAudioPlayer({ audioSrc, isActive }) {
  const audioRef       = useRef(null);
  const syncPromiseRef = useRef(null);
  const resolveRef     = useRef(null);

  // 初始化 promise（组件 mount 时立即建好，不等 audioSrc）
  if (!syncPromiseRef.current) {
    syncPromiseRef.current = new Promise(res => { resolveRef.current = res; });
  }

  // audioSrc 变化时重建 audio src + promise
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    // 重建 promise
    syncPromiseRef.current = new Promise(res => { resolveRef.current = res; });

    if (!audioSrc) return;

    audio.src = audioSrc;
    audio.load();

    const onCanPlay = () => resolveRef.current?.(audio);
    audio.addEventListener('canplay', onCanPlay, { once: true });

    return () => {
      audio.removeEventListener('canplay', onCanPlay);
      audio.pause();
      audio.removeAttribute('src');
      audio.load();
      if (_activeAudio === audio) _activeAudio = null;
    };
  }, [audioSrc]);

  // isActive=false 时暂停
  useEffect(() => {
    if (isActive) return;
    const audio = audioRef.current;
    if (audio && _activeAudio === audio) {
      audio.pause();
      _activeAudio = null;
    }
  }, [isActive]);

  return { audioRef, syncPromiseRef };
}
